with retail as (
select (case when xsimcardno='Corporate' or xbloodgrp='SENA KALYAN' or xbloodgrp='Office Sales' then (select max(xzone) from cadelpoint where xthana=h.xdelpoint) else c.xbloodgrp end) Zone_name,h.xcus,c.xorg,h.xwh,h.xdelivery,xvehicle,xsornum, xconfirmt,h.xchlnum,
(d.xqtychl) total,case when xsimcardno='Corporate'  then d.xqtychl else 0 end Corporate,
case when h.xwh='FINISHED GOODS' and  h.xdelivery='Company' and  d.xtypecat not like '%BULK%' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Fi_OwnTruck,
case when h.xwh='FINISHED GOODS' and  h.xdelivery='Company' and  d.xtypecat like '%BULK%' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Fi_OwnBulk,
