case when h.xwh='Kaligonj Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Ka_OwnTruck,
case when h.xwh='Kaligonj Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Ka_RentalTruck,
case when h.xwh='Kaligonj Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Ka_CustomerTruck,
case when h.xwh='C & B(Faridpur) Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end CN_OwnTruck,
case when h.xwh='C & B(Faridpur) Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end CN_RentalTruck,
