case when h.xwh='Shunamgonj Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Sh_RentalTruck,
case when h.xwh='Shunamgonj Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Sh_CustomerTruck,
case when h.xwh='Daudkandi Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Da_OwnTruck,
case when h.xwh='Daudkandi Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Da_RentalTruck,
case when h.xwh='Daudkandi Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Da_CustomerTruck,
case when h.xwh='Diabari ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Di_OwnTruck,
case when h.xwh='Diabari ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Di_RentalTruck,
case when h.xwh='Diabari ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Di_CustomerTruck,
case when h.xwh='Tekerhat Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Te_OwnTruck,
case when h.xwh='Tekerhat Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Te_RentalTruck,
case when h.xwh='Tekerhat Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Te_CustomerTruck,
case when h.xwh='NogorBari Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end NG_OwnTruck,
case when h.xwh='NogorBari Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end NG_RentalTruck,
