case when h.xwh='Ashugonj Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end As_OwnTruck,
case when h.xwh='Ashugonj Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end As_RentalTruck,
case when h.xwh='Ashugonj Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end As_CustomerTruck,
case when h.xwh='Scan Cement Factory' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Sc_OwnTruck,
case when h.xwh='Scan Cement Factory' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Sc_RentalTruck,
case when h.xwh='Scan Cement Factory' and h.xdelivery='Customer' then d.xqtychl else 0 end Sc_CustomerTruck,
case when h.xwh='Barisal Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Ba_OwnTruck,
case when h.xwh='Barisal Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Ba_RentalTruck,
case when h.xwh='Barisal Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Ba_CustomerTruck,
case when h.xwh='Amin Bazar Ghat' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Am_OwnTruck,
case when h.xwh='Amin Bazar Ghat' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Am_RentalTruck,
case when h.xwh='Amin Bazar Ghat' and h.xdelivery='Customer' then d.xqtychl else 0 end Am_CustomerTruck,
