case when h.xwh='Mongla Cement Factory' and  d.xtypecat like '%BULK%' and  h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is not null then d.xqtychl else 0 end Mo_OwnBulk,
case when h.xwh='Mongla Cement Factory' and h.xdelivery='Company' and (select xvehicle from vmvech where xvehicle=h.xvehicle) is  null then d.xqtychl else 0 end Mo_RentalTruck,
case when h.xwh='Mongla Cement Factory' and h.xdelivery='Customer' then d.xqtychl else 0 end Mo_CustomerTruck
from opchallan h join opchalland d on h.zid=d.zid and h.xchlnum=d.xchlnum
join cacus c on c.zid=h.zid and c.xcus=h.xcus  
where   CONVERT(date,DATEADD(HOUR,-6,xconfirmt)) between '2021-01-01' and '2021-04-30' and xsimcardno<>'Bag Plant'
)
select Zone_name,sum(total)/80 Total ,sum(Corporate)/80 Corporate,
sum(Fi_OwnTruck)/80 Fi_OwnTruck ,sum(Fi_OwnBulk)/80 Fi_OwnBulk, sum(Fi_RentalTruck)/80 Fi_RentalTruck,sum(Fi_CustomerTruck)/80 Fi_CustomerTruck,
sum(NO_OwnTruck)/80 NO_OwnTruck ,sum(NO_RentalTruck)/80 NO_RentalTruck,sum(NO_CustomerTruck)/80 NO_CustomerTruck,
sum(Ka_OwnTruck)/80 Ka_OwnTruck ,sum(Ka_RentalTruck)/80 Ka_RentalTruck,sum(Ka_CustomerTruck)/80 Ka_CustomerTruck,
sum(CN_OwnTruck)/80 CN_OwnTruck ,sum(CN_RentalTruck)/80 CN_RentalTruck,sum(CN_CustomerTruck)/80 CN_CustomerTruck,
sum(Sh_OwnTruck)/80 Sh_OwnTruck ,sum(Sh_RentalTruck)/80 Sh_RentalTruck,sum(Sh_CustomerTruck)/80 Sh_CustomerTruck,
sum(Da_OwnTruck)/80 Da_OwnTruck ,sum(Da_RentalTruck)/80 Da_RentalTruck,sum(Da_CustomerTruck)/80 Da_CustomerTruck,
sum(Di_OwnTruck)/80 Di_OwnTruck ,sum(Di_RentalTruck)/80 Di_RentalTruck,sum(Di_CustomerTruck)/80 Di_CustomerTruck,
sum(Te_OwnTruck)/80 Te_OwnTruck ,sum(Te_RentalTruck)/80 Te_RentalTruck,sum(Te_CustomerTruck)/80 Te_CustomerTruck,
sum(NG_OwnTruck)/80 NG_OwnTruck ,sum(Ng_RentalTruck)/80 NG_RentalTruck,sum(NG_CustomerTruck)/80 NG_CustomerTruck,
sum(As_OwnTruck)/80 As_OwnTruck ,sum(As_RentalTruck)/80 As_RentalTruck,sum(As_CustomerTruck)/80 As_CustomerTruck,
sum(Sc_OwnTruck)/80 Sc_OwnTruck ,sum(Sc_RentalTruck)/80 Sc_RentalTruck,sum(Sc_CustomerTruck)/80 Sc_CustomerTruck,
sum(Ba_OwnTruck)/80 Ba_OwnTruck ,sum(Ba_RentalTruck)/80 Ba_RentalTruck,sum(Ba_CustomerTruck)/80 Ba_CustomerTruck,
sum(Am_OwnTruck)/80 Am_OwnTruck ,sum(Am_RentalTruck)/80 Am_RentalTruck,sum(Am_CustomerTruck)/80 Am_CustomerTruck,
sum(Mo_OwnTruck)/80 Mo_OwnTruck ,sum(Mo_OwnBulk)/80 Mo_OwnBulk ,sum(Mo_RentalTruck)/80 Mo_RentalTruck,sum(Mo_CustomerTruck)/80 Mo_CustomerTruck
from retail a 
group by Zone_name
order by Zone_name


